declare(strict_types=1);

namespace Factuarea\Sdk\Custom\Webhooks;

/**
 * Verifies the authenticity of an incoming Factuarea webhook delivery.
 *
 * Factuarea signs every webhook delivery with HMAC-SHA256 and sends the result
 * in the `Factuarea-Signature` header, using a Stripe-style scheme:
 *
 * ```
 * Factuarea-Signature: t=<unix_timestamp>,v1=<hex_hmac>
 * ```
 *
 * The signed payload is the string `"<unix_timestamp>.<raw_body>"` (the timestamp
 * is bound into the signature to prevent replay attacks). The HMAC is computed
 * with your endpoint's signing secret (`whsec_...`) and rendered as lowercase
 * hexadecimal.
 *
 * During the 24-hour grace window after a secret rotation, deliveries are signed
 * with BOTH the current and the previous secret, producing two `v1` entries:
 *
 * ```
 * Factuarea-Signature: t=<unix>,v1=<hex_current>,v1=<hex_previous>
 * ```
 *
 * To verify safely you only need ONE valid secret: this verifier accepts the
 * delivery if ANY `v1` value matches the HMAC computed with the secret you pass.
 * This is what lets your endpoint keep working throughout a rotation: configure
 * the verifier with the new secret and old deliveries still verify (the header
 * still carries a `v1` signed with the old secret), and vice versa.
 *
 * The timestamp is validated against a configurable tolerance (default 5
 * minutes) so that captured-and-replayed deliveries are rejected. All HMAC
 * comparisons are constant-time (`hash_equals`). The signing secret is never
 * logged nor included in any exception message.
 *
 * Usage:
 *
 * ```php
 * use Factuarea\Sdk\Custom\Webhooks\WebhookVerifier;
 *
 * $verifier = new WebhookVerifier();
 * $rawBody = file_get_contents('php://input');
 * $signature = $_SERVER['HTTP_FACTUAREA_SIGNATURE'] ?? '';
 *
 * try {
 *     $verifier->verify($rawBody, $signature, getenv('FACTUAREA_WEBHOOK_SECRET'));
 *     // signature is valid — decode and handle the event
 *     $event = json_decode($rawBody, true);
 * } catch (WebhookSignatureException $e) {
 *     http_response_code(400);
 * }
 * ```
 */
final class WebhookVerifier
{
    /** Header that carries the webhook signature. */
    public const SIGNATURE_HEADER = 'Factuarea-Signature';

    /** Default allowed clock skew between signing and verification (seconds). */
    public const DEFAULT_TOLERANCE_SECONDS = 300;

    /**
     * Verify a webhook delivery and return the decoded event payload.
     *
     * @param  string  $payload  The exact raw request body, byte-for-byte as received.
     * @param  string  $signatureHeader  The value of the `Factuarea-Signature` header.
     * @param  string  $secret  The endpoint signing secret (`whsec_...`).
     * @param  int  $toleranceSeconds  Maximum allowed age of the delivery in seconds.
     * @param  ?int  $now  Override the current unix time (testing); defaults to time().
     * @return array<string, mixed> The decoded JSON event payload.
     *
     * @throws WebhookSignatureException If the signature, timestamp, or payload is invalid.
     */
    public function verify(
        string $payload,
        string $signatureHeader,
        #[\SensitiveParameter] string $secret,
        int $toleranceSeconds = self::DEFAULT_TOLERANCE_SECONDS,
        ?int $now = null,
    ): array {
        $this->assertSignature($payload, $signatureHeader, $secret, $toleranceSeconds, $now);

        /** @var array<string, mixed> $decoded */
        $decoded = json_decode($payload, true, 512, JSON_THROW_ON_ERROR);

        return $decoded;
    }

    /**
     * Verify a webhook delivery without decoding the payload.
     *
     * Prefer {@see verify()} unless you want to control deserialization yourself.
     *
     * @throws WebhookSignatureException If the signature, timestamp, or payload is invalid.
     */
    public function assertSignature(
        string $payload,
        string $signatureHeader,
        #[\SensitiveParameter] string $secret,
        int $toleranceSeconds = self::DEFAULT_TOLERANCE_SECONDS,
        ?int $now = null,
    ): void {
        if (trim($signatureHeader) === '') {
            throw WebhookSignatureException::missingHeader();
        }

        $parsed = $this->parseHeader($signatureHeader);
        $timestamp = $parsed['timestamp'];
        $signatures = $parsed['signatures'];

        if ($signatures === []) {
            throw WebhookSignatureException::malformedHeader();
        }

        $currentTime = $now ?? time();
        if (abs($currentTime - $timestamp) > $toleranceSeconds) {
            throw WebhookSignatureException::timestampTooOld($toleranceSeconds);
        }

        $signedPayload = $timestamp.'.'.$payload;
        $expected = hash_hmac('sha256', $signedPayload, $secret);

        foreach ($signatures as $candidate) {
            if (hash_equals($expected, $candidate)) {
                return;
            }
        }

        throw WebhookSignatureException::noMatchingSignature();
    }

    /**
     * Parse a `t=<unix>,v1=<hex>[,v1=<hex>]` header into its timestamp and
     * the list of advertised `v1` signatures.
     *
     * @return array{timestamp: int, signatures: list<string>}
     *
     * @throws WebhookSignatureException If no `t=` segment is present.
     */
    private function parseHeader(string $header): array
    {
        $timestamp = null;
        $signatures = [];

        foreach (explode(',', $header) as $segment) {
            $segment = trim($segment);
            if ($segment === '') {
                continue;
            }

            $eq = strpos($segment, '=');
            if ($eq === false) {
                continue;
            }

            $key = substr($segment, 0, $eq);
            $value = substr($segment, $eq + 1);

            if ($key === 't') {
                if ($value === '' || (string) (int) $value !== $value) {
                    throw WebhookSignatureException::malformedHeader();
                }
                $timestamp = (int) $value;
            } elseif ($key === 'v1' && $value !== '') {
                $signatures[] = $value;
            }
        }

        if ($timestamp === null) {
            throw WebhookSignatureException::malformedHeader();
        }

        return ['timestamp' => $timestamp, 'signatures' => $signatures];
    }
}
